from __future__ import annotations

from dataclasses import dataclass
from typing import Iterable


class CronParseError(ValueError):
    """Raised when a cron expression cannot be parsed."""


@dataclass(frozen=True)
class CronField:
    name: str
    expression: str
    min_value: int
    max_value: int
    values: tuple[int, ...]

    def is_wildcard(self) -> bool:
        return self.values == tuple(range(self.min_value, self.max_value + 1))

    def is_single_value(self) -> bool:
        return len(self.values) == 1

    def single_value(self) -> int:
        if not self.is_single_value():
            raise CronParseError(f"{self.name} is not a single value")
        return self.values[0]


@dataclass(frozen=True)
class CronSchedule:
    minute: CronField
    hour: CronField
    day_of_month: CronField
    month: CronField
    day_of_week: CronField

    def describe(self) -> str:
        if self._is_every_minute():
            return "Every minute"

        if self._is_simple_minute_step():
            step = _extract_step(self.minute.expression)
            return f"Every {step} minutes"

        if self._is_simple_hour_step():
            step = _extract_step(self.hour.expression)
            minute = self.minute.single_value()

            if minute == 0:
                return f"Every {step} hours, on the hour"

            return f"Every {step} hours, at {minute:02d} minutes past"

        parts: list[str] = [self._describe_time()]
        parts.extend(self._describe_date_parts())

        return " ".join(parts)

    def _is_every_minute(self) -> bool:
        return (
            self.minute.is_wildcard()
            and self.hour.is_wildcard()
            and self.day_of_month.is_wildcard()
            and self.month.is_wildcard()
            and self.day_of_week.is_wildcard()
        )

    def _is_simple_minute_step(self) -> bool:
        return (
            self.minute.expression.startswith("*/")
            and self.hour.is_wildcard()
            and self.day_of_month.is_wildcard()
            and self.month.is_wildcard()
            and self.day_of_week.is_wildcard()
        )

    def _is_simple_hour_step(self) -> bool:
        return (
            self.minute.is_single_value()
            and self.hour.expression.startswith("*/")
            and self.day_of_month.is_wildcard()
            and self.month.is_wildcard()
            and self.day_of_week.is_wildcard()
        )

    def _describe_time(self) -> str:
        if not self.minute.is_single_value() or not self.hour.is_single_value():
            return self._describe_general_time()

        minute = self.minute.single_value()
        hour = self.hour.single_value()

        if hour == 0 and minute == 0:
            return "At midnight"

        return f"At {hour:02d}:{minute:02d}"

    def _describe_general_time(self) -> str:
        minute_text = _describe_field_values(self.minute)
        hour_text = _describe_field_values(self.hour)

        if self.hour.is_wildcard():
            return f"At {minute_text} minutes past every hour"

        if self.minute.is_wildcard():
            return f"Every minute during hour {hour_text}"

        return f"At minute {minute_text} during hour {hour_text}"

    def _describe_date_parts(self) -> list[str]:
        parts: list[str] = []

