def parse_cron(expression: str) -> CronSchedule:
    fields = expression.split()

    if len(fields) != 5:
        raise CronParseError(
            "Cron expression must contain exactly 5 fields: "
            "minute hour day_of_month month day_of_week"
        )

    minute = parse_field("minute", fields[0], 0, 59)
    hour = parse_field("hour", fields[1], 0, 23)
    day_of_month = parse_field("day_of_month", fields[2], 1, 31)
    month = parse_field("month", fields[3], 1, 12)
    day_of_week = parse_field("day_of_week", fields[4], 0, 6)

    return CronSchedule(
        minute=minute,
        hour=hour,
        day_of_month=day_of_month,
        month=month,
        day_of_week=day_of_week,
    )


def parse_field(name: str, expression: str, min_value: int, max_value: int) -> CronField:
    if not expression:
        raise CronParseError(f"{name} field cannot be empty")

    values: set[int] = set()

    for part in expression.split(","):
        values.update(_parse_field_part(name, part, min_value, max_value))

    if not values:
        raise CronParseError(f"{name} field did not produce any values")

    return CronField(
        name=name,
        expression=expression,
        min_value=min_value,
        max_value=max_value,
        values=tuple(sorted(values)),
    )


def _parse_field_part(
    name: str,
    part: str,
    min_value: int,
    max_value: int,
) -> set[int]:
    if not part:
        raise CronParseError(f"{name} field contains an empty list item")

    base_expression, step = _split_step(name, part)
    start, end = _parse_base_range(name, base_expression, min_value, max_value)

    if step <= 0:
        raise CronParseError(f"{name} step must be greater than 0")

    return set(range(start, end + 1, step))


def _split_step(name: str, part: str) -> tuple[str, int]:
    if "/" not in part:
        return part, 1

    pieces = part.split("/")

    if len(pieces) != 2 or not pieces[0] or not pieces[1]:
        raise CronParseError(f"{name} has invalid step syntax: {part!r}")

    return pieces[0], _parse_int(name, pieces[1])


def _parse_base_range(
    name: str,
    expression: str,
    min_value: int,
    max_value: int,
) -> tuple[int, int]:
    if expression == "*":
        return min_value, max_value

    if "-" in expression:
        return _parse_explicit_range(name, expression, min_value, max_value)

    value = _parse_int(name, expression)
    _validate_range(name, value, min_value, max_value)
    return value, value


def _parse_explicit_range(
    name: str,
    expression: str,
    min_value: int,
    max_value: int,
) -> tuple[int, int]:
    pieces = expression.split("-")

    if len(pieces) != 2 or not pieces[0] or not pieces[1]:
        raise CronParseError(f"{name} has invalid range syntax: {expression!r}")

    start = _parse_int(name, pieces[0])
    end = _parse_int(name, pieces[1])

    _validate_range(name, start, min_value, max_value)
    _validate_range(name, end, min_value, max_value)

    if start > end:
        raise CronParseError(f"{name} range start cannot be greater than range end")

    return start, end


def _parse_int(name: str, value: str) -> int:
    try:
        return int(value)
    except ValueError as error:
        raise CronParseError(f"{name} contains a non-integer value: {value!r}") from error


def _validate_range(name: str, value: int, min_value: int, max_value: int) -> None:
    if value < min_value or value > max_value:
        raise CronParseError(
            f"{name} value {value} is outside allowed range "
            f"{min_value}-{max_value}"
        )


def _extract_step(expression: str) -> int:
    return int(expression.split("/", 1)[1])


def _describe_field_values(field: CronField) -> str:
    return _join_english([str(value) for value in field.values])


def _describe_days_of_week(field: CronField) -> str:
    if field.expression == "1-5":
        return "Monday through Friday"

    day_names = [_DAY_NAMES[value] for value in field.values]
    return _join_english(day_names)


def _ordinal_list(values: Iterable[int]) -> str:
    return _join_english([_ordinal(value) for value in values])


def _ordinal(value: int) -> str:
    if 10 <= value % 100 <= 20:
        suffix = "th"
    else:
        suffix = {1: "st", 2: "nd", 3: "rd"}.get(value % 10, "th")

    return f"{value}{suffix}"


def _join_english(items: list[str]) -> str:
    if not items:
        return ""

    if len(items) == 1:
        return items[0]

    if len(items) == 2:
        return f"{items[0]} and {items[1]}"

    return f"{', '.join(items[:-1])}, and {items[-1]}"


